## Common patterns

### Like/favorite buttons

A common use case for toggle buttons in social features:

```jsx-live-dev
const App = () => {
  const [likeCount, setLikeCount] = useState(42);
  const [isLiked, setIsLiked] = useState(false);

  const handleLikeToggle = (selected) => {
    setIsLiked(selected);
    setLikeCount((count) => selected ? count + 1 : count - 1);
  };

  return (
    <Stack direction="row" gap="300" alignItems="center">
      <IconToggleButton
        isSelected={isLiked}
        onChange={handleLikeToggle}
        aria-label={isLiked ? "Unlike" : "Like"}
        colorPalette="critical"
      >
        <Icons.ThumbUp />
      </IconToggleButton>
      <Text fontSize="sm">{likeCount} likes</Text>
    </Stack>
  );
}
```

### Toolbar actions

Toggle buttons work well in toolbars for formatting and view options:

```jsx-live-dev
const App = () => {
  const [bold, setBold] = useState(false);
  const [italic, setItalic] = useState(false);
  const [underline, setUnderline] = useState(false);

  return (
    <Stack direction="column" gap="400">
      <Stack direction="row" gap="100" alignItems="center">
        <IconToggleButton
          isSelected={bold}
          onChange={setBold}
          aria-label="Toggle bold"
          variant="ghost"
        >
          <Icons.FormatBold />
        </IconToggleButton>
        <IconToggleButton
          isSelected={italic}
          onChange={setItalic}
          aria-label="Toggle italic"
          variant="ghost"
        >
          <Icons.FormatItalic />
        </IconToggleButton>
        <IconToggleButton
          isSelected={underline}
          onChange={setUnderline}
          aria-label="Toggle underline"
          variant="ghost"
        >
          <Icons.FormatUnderlined />
        </IconToggleButton>
      </Stack>
      <Text fontSize="sm">
        Active: {[bold && 'Bold', italic && 'Italic', underline && 'Underline'].filter(Boolean).join(', ') || 'None'}
      </Text>
    </Stack>
  );
}
```



### Async state updates

Handle asynchronous operations when toggling state:

```jsx-live-dev
const App = () => {
  const [isSubscribed, setIsSubscribed] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const handleToggle = async (selected) => {
    setIsLoading(true);
    // Simulate API call
    await new Promise(resolve => setTimeout(resolve, 1000));
    setIsSubscribed(selected);
    setIsLoading(false);
  };

  return (
    <Stack direction="row" gap="400" alignItems="center">
      <IconToggleButton
        isSelected={isSubscribed}
        onChange={handleToggle}
        isDisabled={isLoading}
        aria-label={isSubscribed ? "Unsubscribe" : "Subscribe"}
        colorPalette="info"
      >
        <Icons.Notifications />
      </IconToggleButton>
      <Text fontSize="sm">
        {isLoading ? 'Processing...' : isSubscribed ? 'Subscribed' : 'Not subscribed'}
      </Text>
    </Stack>
  );
}
```

## Testing your implementation

These examples demonstrate how to test your implementation when using IconToggleButton in your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the component renders with expected accessibility attributes

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { IconToggleButton, NimbusProvider } from "@commercetools/nimbus";
import { ThumbUp } from "@commercetools/nimbus-icons";

describe("IconToggleButton - Basic rendering", () => {
  it("renders with aria-label", () => {
    render(
      <NimbusProvider>
        <IconToggleButton aria-label="Like this post">
          <ThumbUp />
        </IconToggleButton>
      </NimbusProvider>
    );

    expect(
      screen.getByRole("button", { name: /like this post/i })
    ).toBeInTheDocument();
  });

  it("renders with pressed state attribute", () => {
    render(
      <NimbusProvider>
        <IconToggleButton aria-label="Like">
          <ThumbUp />
        </IconToggleButton>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /like/i });
    expect(button).toHaveAttribute("aria-pressed", "false");
  });

  it("renders unselected by default", () => {
    render(
      <NimbusProvider>
        <IconToggleButton aria-label="Star">
          <ThumbUp />
        </IconToggleButton>
      </NimbusProvider>
    );

    const button = screen.getByRole("button");
    expect(button).toHaveAttribute("aria-pressed", "false");
  });
});
```

